import React, { useState, useEffect } from 'react';
import { getEmployees, deleteEmployee } from '../api';
import '../styles/EmployeeList.css';

const EmployeeList = ({ onEdit, refreshTrigger }) => {
  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [page, setPage] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterCountry, setFilterCountry] = useState('');

  const itemsPerPage = 10;

  useEffect(() => {
    fetchEmployees();
  }, [refreshTrigger]);

  const fetchEmployees = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await getEmployees();
      setEmployees(response.data);
    } catch (err) {
      setError('Failed to fetch employees: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this employee?')) {
      try {
        await deleteEmployee(id);
        fetchEmployees();
      } catch (err) {
        alert('Failed to delete employee: ' + err.message);
      }
    }
  };

  // Filter employees
  const filteredEmployees = employees.filter((emp) => {
    const matchesSearch =
      emp.first_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      emp.last_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      emp.job_title?.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesCountry = !filterCountry || emp.country === filterCountry;

    return matchesSearch && matchesCountry;
  });

  // Pagination
  const totalPages = Math.ceil(filteredEmployees.length / itemsPerPage);
  const startIdx = (page - 1) * itemsPerPage;
  const paginatedEmployees = filteredEmployees.slice(startIdx, startIdx + itemsPerPage);

  // Get unique countries for filter
  const countries = [...new Set(employees.map((emp) => emp.country).filter(Boolean))].sort();

  if (loading) {
    return <div className="loading-container">Loading employees...</div>;
  }

  return (
    <div className="employee-list-container">
      <div className="list-header">
        <h2>Employees Database</h2>
        <p className="total-count">Total: {employees.length} employees</p>
      </div>

      {error && <div className="error-message">{error}</div>}

      <div className="filters-section">
        <input
          type="text"
          placeholder="Search by name or job title..."
          value={searchTerm}
          onChange={(e) => {
            setSearchTerm(e.target.value);
            setPage(1);
          }}
          className="search-input"
        />

        <select
          value={filterCountry}
          onChange={(e) => {
            setFilterCountry(e.target.value);
            setPage(1);
          }}
          className="filter-select"
        >
          <option value="">All Countries</option>
          {countries.map((country) => (
            <option key={country} value={country}>
              {country}
            </option>
          ))}
        </select>
      </div>

      <div className="table-responsive">
        <table className="employee-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Name</th>
              <th>Job Title</th>
              <th>Country</th>
              <th>Salary</th>
              <th>Department</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {paginatedEmployees.length > 0 ? (
              paginatedEmployees.map((employee) => (
                <tr key={employee.id}>
                  <td>{employee.id}</td>
                  <td className="employee-name">
                    {employee.first_name} {employee.last_name}
                  </td>
                  <td>{employee.job_title}</td>
                  <td>{employee.country}</td>
                  <td className="salary-cell">
                    ${employee.salary?.toLocaleString() || 'N/A'}
                  </td>
                  <td>{employee.department || 'N/A'}</td>
                  <td className="action-buttons">
                    <button
                      onClick={() => onEdit(employee)}
                      className="btn-edit"
                      title="Edit employee"
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDelete(employee.id)}
                      className="btn-delete"
                      title="Delete employee"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="7" className="no-data">
                  No employees found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="pagination">
          <button
            onClick={() => setPage(Math.max(1, page - 1))}
            disabled={page === 1}
            className="pagination-btn"
          >
            Previous
          </button>

          <div className="page-info">
            Page {page} of {totalPages}
          </div>

          <button
            onClick={() => setPage(Math.min(totalPages, page + 1))}
            disabled={page === totalPages}
            className="pagination-btn"
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

export default EmployeeList;
